import React from 'react';
import { Sun, Moon } from 'lucide-react';
import { useTheme } from '../context/ThemeContext';

const ThemeToggle = () => {
  const { isDarkMode, toggleTheme } = useTheme();

  return (
    <button
      onClick={toggleTheme}
      className="p-2.5 rounded-xl border border-[var(--surface-border)] 
                 bg-[var(--input-bg)] hover:bg-[var(--accent-glow)] 
                 transition-all duration-300 group shadow-sm flex items-center justify-center"
      title={isDarkMode ? "Switch to Light Mode" : "Switch to Dark Mode"}
    >
      {isDarkMode ? (
        <Sun 
          size={18} 
          className="text-[var(--accent-primary)] group-hover:rotate-45 transition-transform duration-500" 
        />
      ) : (
        <Moon 
          size={18} 
          className="text-[var(--accent-secondary)] group-hover:-rotate-12 transition-transform duration-500" 
        />
      )}
    </button>
  );
};

export default ThemeToggle;
